SELECT ROUND(
  TIMESTAMPDIFF(MINUTE,
    (SELECT MAX(timestamp) FROM cost_facts),
    (SELECT MAX(timestamp) FROM token_ledger)
  ) / 60.0, 1
) AS rollup_lag_hours

SELECT ROUND(
  TIMESTAMPDIFF(SECOND,
    (SELECT MAX(assembled_at) FROM wms_intervals WHERE phase_source = 'classifier'),
    NOW()
  ) / 60.0, 0
) AS classify_lag_min

options.getOption:
const allSeries = context.panel.data.series;
if (!allSeries || allSeries.length < 1) return { series: [] };

const fld = (s, name) => {
  const f = s.fields.find(x => x.name === name);
  if (!f) return [];
  const v = f.values;
  return (v && v.buffer) ? v.buffer : (v || []);
};

const links = [];
const nodeSet = new Set();

for (const s of allSeries) {
  if (!s || !s.fields || s.fields.length < 3) continue;
  const sources = fld(s, 'source');
  const targets = fld(s, 'target');
  const values  = fld(s, 'value');
  for (let i = 0; i < sources.length; i++) {
    const v = parseFloat(values[i]) || 0;
    const src = String(sources[i]);
    const tgt = String(targets[i]);
    if (v > 0 && src !== tgt) {
      links.push({ source: src, target: tgt, value: v });
      nodeSet.add(src);
      nodeSet.add(tgt);
    }
  }
}
if (!links.length) return { series: [] };

const colorMap = {
  'total spend': '#666666',
  'direct': '#22C55E',
  'inferred': '#3B82F6',
  'recovered': '#A855F7',
  'unallocated': '#E02F44',
  'outcome': '#22C55E',
  'workunit': '#3B82F6',
  'legacy v1': '#9E9E9E',
  'unattributed': '#E02F44'
};

const outgoing = {};
const incoming = {};
for (const l of links) {
  outgoing[l.source] = (outgoing[l.source] || 0) + l.value;
  incoming[l.target] = (incoming[l.target] || 0) + l.value;
}

const nodes = Array.from(nodeSet).map(name => ({
  name,
  value: Math.max(outgoing[name] || 0, incoming[name] || 0),
  itemStyle: { color: colorMap[name] || '#888888' }
}));

return {
  tooltip: {
    trigger: 'item',
    formatter: p => {
      if (p.dataType === 'edge')
        return p.data.source + ' \u2192 ' + p.data.target + ': $' + p.data.value.toFixed(2);
      return p.name + '<br/>$' + ((p.data.value || 0).toFixed(2));
    }
  },
  series: [{
    type: 'sankey',
    layout: 'none',
    emphasis: { focus: 'adjacency' },
    nodeAlign: 'left',
    data: nodes,
    links: links,
    label: {
      show: true, position: 'right', fontSize: 11,
      formatter: p => p.name + '\n$' + ((p.value || 0).toFixed(0))
    },
    lineStyle: { color: 'gradient', opacity: 0.5 },
    nodeGap: 12,
    nodeWidth: 20
  }]
};
